#!/usr/bin/env bash
# Populate the gitignored font dir. Idempotent; called by build.sh and by CI.
# Noto Serif CJK SC (SIL OFL) is fetched. IDC.ttf (IDS operators U+2FF0-2FFF)
# has no upstream URL, so it is decoded from the embedded base64 below.
set -euo pipefail
cd "$(dirname "$0")"
FONTS=vendor/dual-typst/assets/fonts
mkdir -p "$FONTS"

NOTO="$FONTS/NotoSerifCJKsc-Regular.otf"
[ -f "$NOTO" ] || curl -fsSL -o "$NOTO" \
  "https://github.com/notofonts/noto-cjk/raw/main/Serif/OTF/SimplifiedChinese/NotoSerifCJKsc-Regular.otf"

if [ ! -f "$FONTS/IDC.ttf" ]; then
python3 - "$FONTS/IDC.ttf" <<'PY'
import base64, sys
b64 = """

"""
open(sys.argv[1], "wb").write(base64.b64decode(b64))
PY
fi
echo "fonts ready in $FONTS"
